      let daysToAdd = 0;
      if (intervalInDays <= 15) {
        daysToAdd = 30;
      } else if (intervalInDays <= 30) {
        daysToAdd = 45;
      } else if (intervalInDays <= 45) {
        daysToAdd = 60;
      }

      return daysToAdd !== 0 ? moment(qrtEncounterDate).add(daysToAdd, 'days').toDate() : null;
    }

