      const isGF1InLatestGMEncounter = latestGMEncounter.getObservationReadableValue("Growth Faltering") == "GF1";

      if ((takenToMedicalFacility || isSAMInLatestGMEncounter || !isGF1InLatestGMEncounter ) && !_.isNil(visitDate)) { 
        scheduleBuilder.add({
