"use strict";
({params, imports}) => {
    const programEncounter = params.entity;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
        programEncounter
    });
    const moment = imports.moment;
    const _ = imports.lodash;

    function visitAlreadyScheduled(encounterType, earliestDate) {
        const earliestDateMoment = moment(earliestDate);
        const isVisitScheduled = programEncounter.programEnrolment.getEncountersOfType(encounterType)
            .some((enc) =>
                enc.voided === false &&
                moment(enc.earliestVisitDateTime).isSame(earliestDateMoment, 'day')
            );

        return isVisitScheduled;
    }

    const isTreatmentNotAtHome = programEncounter.getObservationReadableValue("What is the treatment advise for the SAM/MAM/GF2 child?") ? programEncounter.getObservationReadableValue("What is the treatment advise for the SAM/MAM/GF2 child?") != "Treatment at home" : false;
    const isTreatmentAtHome = programEncounter.getObservationReadableValue("What is the treatment advise for the SAM/MAM/GF2 child?") ? programEncounter.getObservationReadableValue("What is the treatment advise for the SAM/MAM/GF2 child?") == "Treatment at home" : false;
    const isSAM = programEncounter.getObservationReadableValue("Nutritional Status") == "SAM";
    const isGF1 = programEncounter.getObservationReadableValue("Growth Faltering") == "GF1";

    const growthMonitoringEarliestDate = moment(programEncounter.earliestVisitDateTime).add(1, 'month').startOf('month').toDate();
    const qrtEarliestDate = moment(programEncounter.encounterDateTime).startOf('day').toDate();
    const childHomeVisitEarliestDate = moment(programEncounter.encounterDateTime).add(15, 'days').startOf('day').toDate();

    // Growth Monitoring
    if(programEncounter.programEnrolment.individual.getAgeInYears() < 5 && !visitAlreadyScheduled('Growth Monitoring', growthMonitoringEarliestDate)) {
        scheduleBuilder.add({
            name: 'Growth Monitoring',
            encounterType: 'Growth Monitoring',
            earliestDate: growthMonitoringEarliestDate,
            maxDate:  moment(growthMonitoringEarliestDate).endOf('month').toDate()
        });
    }

    // QRT Child or Child Home Visit
    if((isTreatmentNotAtHome || isSAM) && !visitAlreadyScheduled('QRT Child', qrtEarliestDate)) {
        scheduleBuilder.add({
            name: 'QRT Child',
            encounterType: 'QRT Child',
            earliestDate: qrtEarliestDate,
            maxDate: moment(qrtEarliestDate).add(30, 'days').endOf('day').toDate()
        });
    }
    else if ((isTreatmentAtHome || isGF1 ) && !visitAlreadyScheduled('Child Home Visit', childHomeVisitEarliestDate) && !isSAM){
        scheduleBuilder.add({
            name: 'Child Home Visit',
            encounterType: 'Child Home Visit',
            earliestDate: childHomeVisitEarliestDate,
            maxDate: moment(childHomeVisitEarliestDate).add(7, 'days').endOf('day').toDate()
        });
    }

    return scheduleBuilder.getAll();
};

