({params, imports}) => {
    const programEncounter = params.entity;
    const _ = imports.lodash;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
        programEncounter
    });


    function getPWHomeVisitDate(qrtEncounterDate) {
        const intervalInDays = imports.moment(programEncounter.earliestVisitDateTime).diff(imports.moment(qrtEncounterDate), 'days');

        let daysToAdd = 0;
        if (intervalInDays <= 15) {
            daysToAdd = 30;
        } else if (intervalInDays <= 30) {
            daysToAdd = 45;
        } else if (intervalInDays <= 45) {
            daysToAdd = 60;
        }

        return daysToAdd !== 0 ? imports.moment(qrtEncounterDate).add(daysToAdd, 'days').toDate() : null;
    }


    function lastfilledEncounter(encounterType) {
        const lastVisitEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, false);
        const latestEncounter = _.chain(lastVisitEncounters)
            .filter((encounter) => encounter.encounterDateTime && encounter.voided == false)
            .maxBy((encounter) => encounter.encounterDateTime)
            .value();
        return latestEncounter;
    }


    const qrtEncounter = lastfilledEncounter('QRT PW');
    if (qrtEncounter) {
        const qrtEncounterDate = qrtEncounter ? imports.moment(qrtEncounter.encounterDateTime).toDate() : null;
        const visitDate = getPWHomeVisitDate(qrtEncounterDate);

         let isEditScenario = programEncounter.programEnrolment.encounters.some((enc) => 
            enc.encounterType.name === 'PW Home Visit' && 
            enc.voided === false && 
            imports.moment(enc.earliestVisitDateTime).isSame(visitDate, 'day')
          );

        if (visitDate && !isEditScenario) {
            scheduleBuilder
                .add({
                    name: "PW Home Visit",
                    encounterType: "PW Home Visit",
                    earliestDate: imports.moment(visitDate).startOf('day').toDate(),
                    maxDate: imports.moment(visitDate).add(7, 'days').endOf('day').toDate()
                });
        }
    }


    const isHighRiskCondition = programEncounter.programEnrolment.getObservationReadableValue('High risk condition');
    const currentlyActiveInProgram = !programEncounter.programEnrolment.programExitDateTime;
    const supervisorPWEncounter = lastfilledEncounter('Supervisor PW Home Visit');
    let spwEncounterDate;
    let spwEncounterMonth;
    if (supervisorPWEncounter) {
        spwEncounterDate = imports.moment(supervisorPWEncounter.encounterDateTime).toDate();
        spwEncounterMonth = imports.moment(spwEncounterDate).month();
    }      
    const earliestDate = moment(programEncounter.encounterDateTime);
    const earliestDateMonth = earliestDate.month();

    let isAlreadyScheduled = programEncounter.programEnrolment.encounters.some((enc) =>
        enc.encounterType.name == 'Supervisor PW Home Visit' &&
        enc.voided == false &&
        moment(enc.earliestVisitDateTime).isSame(earliestDate, 'day')
    );
    if((spwEncounterMonth !== earliestDateMonth) && !isAlreadyScheduled && isHighRiskCondition && isHighRiskCondition.length > 0 && currentlyActiveInProgram) {

        scheduleBuilder.add({
            name: 'Supervisor PW Home Visit',
            encounterType: 'Supervisor PW Home Visit',
            earliestDate: earliestDate.startOf('day').toDate(),
            maxDate:  earliestDate.endOf('month').toDate()
        });
    }
    return scheduleBuilder.getAll();
}

