"use strict";
({params, imports}) => {
    const programEncounter = params.entity;
    const _ = imports.lodash;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
        programEncounter
    });

    const takenToMedicalFacility = programEncounter.getObservationReadableValue("QRT facilitated child to medical facility?") == "Yes";
    const referredToNRC = programEncounter.getObservationReadableValue("Advice given") == "Referred to NRC";

    function lastfilledEncounter(encounterType) {
        const lastVisitEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, false);
        const latestEncounter = _.chain(lastVisitEncounters)
            .filter((encounter) => encounter.encounterDateTime && encounter.voided == false)
            .maxBy((encounter) => encounter.encounterDateTime)
            .value();
        return latestEncounter;
    }

    const qrtEncounter = lastfilledEncounter('Growth Monitoring');
    if (qrtEncounter) {
        const isSAMInLastGM = qrtEncounter ? qrtEncounter.getObservationReadableValue("Nutritional Status") == "SAM" : false;
        if (takenToMedicalFacility || isSAMInLastGM) {
            scheduleBuilder.add({
                name: 'Child Home Visit',
                encounterType: 'Child Home Visit',
                earliestDate: imports.moment(programEncounter.encounterDateTime).add(15, 'days').startOf('day').toDate(),
                maxDate: imports.moment(programEncounter.encounterDateTime).add(22, 'days').endOf('day').toDate()
            });
        }
  }

    if(referredToNRC){
          scheduleBuilder.add({
                name: 'NRC Admission',
                encounterType: 'NRC Admission',
                earliestDate: imports.moment(programEncounter.encounterDateTime).startOf('day').toDate(),
                maxDate: imports.moment(programEncounter.encounterDateTime).add(60, 'days').endOf('day').toDate()
            });
    }


    return scheduleBuilder.getAll();
};

