({params, imports}) => {
    const encounter = params.entity;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
        encounter
    });
    const moment = imports.moment;
    const _ = imports.lodash;

    const earliestDate = moment(encounter.earliestVisitDateTime).add(1, 'month').startOf('month');
    const currentlyActive= !encounter.individual.voided;


     let isAlreadyScheduled = _.some(encounter.individual.encounters, (enc) =>
    enc.encounterType.name === 'Supervisor Growth Monitoring Session' &&
    enc.voided === false &&
    moment(enc.earliestVisitDateTime).isSame(earliestDate, 'day')
);


    if(!isAlreadyScheduled && currentlyActive) {
        scheduleBuilder.add({
            name: 'Supervisor Growth Monitoring Session',
            encounterType: 'Supervisor Growth Monitoring Session',
            earliestDate: earliestDate.toDate(),
            maxDate:  earliestDate.endOf('month').toDate()
        });
    }

    return scheduleBuilder.getAll();
}

