    let isVHSNDAlreadyScheduled = individual.encounters.some((enc) =>
        enc.encounterType.name === 'Supervisor VHSND Visit' &&
        enc.voided === false &&
        moment(enc.earliestVisitDateTime).isSame(startDate, 'day')
    );

    let isGrowthMonitoringAlreadyScheduled = individual.encounters.some((enc) =>
        enc.encounterType.name === 'Supervisor Growth Monitoring Session' &&
        enc.voided === false &&
        moment(enc.earliestVisitDateTime).isSame(startDate, 'day')
    );

    if(!isVHSNDAlreadyScheduled) {
        const earliestDate = moment(startDate).startOf('month');
        scheduleBuilder.add({
            name: 'Supervisor VHSND Visit',
            encounterType: 'Supervisor VHSND Visit',
            earliestDate: earliestDate.toDate(),
            maxDate:  earliestDate.endOf('month').toDate()
        });
    }
    if(!isGrowthMonitoringAlreadyScheduled) {
        const earliestDate = moment(startDate).startOf('month');
        scheduleBuilder.add({
            name: 'Supervisor Growth Monitoring',
            encounterType: 'Supervisor Growth Monitoring Session',
            earliestDate: earliestDate.toDate(),
            maxDate:  earliestDate.endOf('month').toDate()
        });
    }

    return scheduleBuilder.getAll();
}

