    const programEncounter = params.entity;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
        programEncounter
    });

    const cancelReasonIsOther = new imports.rulesConfig.RuleCondition({programEncounter}).when.valueInCancelEncounter("f0a6eee8-3421-46cb-a500-309127e98231").containsAnswerConceptName("f169230d-809b-4d06-9ccb-96586977bb68").matches();

    function getChildHomeVisitDate(qrtEncounterDate) {
        const intervalInDays = imports.moment(programEncounter.earliestVisitDateTime).diff(imports.moment(qrtEncounterDate), 'days');

        let daysToAdd = 0;
        if (intervalInDays <= 15) {
            daysToAdd = 30;
        } else if (intervalInDays <= 30) {
            daysToAdd = 45;
        } else if (intervalInDays <= 45) {
            daysToAdd = 60;
        }

        return daysToAdd !== 0 ? imports.moment(qrtEncounterDate).add(daysToAdd, 'days').toDate() : null;
    }

    function lastfilledEncounter(encounterType) {
        const lastVisitEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, false);
        const latestEncounter = _.chain(lastVisitEncounters)
            .filter((encounter) => encounter.encounterDateTime && encounter.voided == false)
            .maxBy((encounter) => encounter.encounterDateTime)
            .value();
        return latestEncounter;
    }

    const qrtEncounter = lastfilledEncounter('QRT Child');
    if (qrtEncounter && programEncounter.name != 'Child Home Visit - Post NRC') {
        const qrtEncounterDate = qrtEncounter ? imports.moment(qrtEncounter.encounterDateTime).toDate() : null;
        const visitDate = getChildHomeVisitDate(qrtEncounterDate);
        const takenToMedicalFacility = qrtEncounter.getObservationReadableValue("QRT facilitated child to medical facility?") == "Yes";
        const latestGMEncounter = lastfilledEncounter('Growth Monitoring');
        const isSAMInLatestGMEncounter = latestGMEncounter.getObservationReadableValue("Nutritional Status") == "SAM";
        const isGF1InLatestGMEncounter = latestGMEncounter.getObservationReadableValue("Growth Faltering") == "GF1";

        if ((takenToMedicalFacility || isSAMInLatestGMEncounter || !isGF1InLatestGMEncounter)  && cancelReasonIsOther  && !_.isNil(visitDate)) {
            scheduleBuilder.add({
                name: 'Child Home Visit',
                encounterType: 'Child Home Visit',
                earliestDate: imports.moment(visitDate).startOf('day').toDate(),
                maxDate: imports.moment(visitDate).add(7, 'days').endOf('day').toDate(),
                visitCreationStrategy: "createNew"

            });
        }
    }

        if (programEncounter.name == 'Child Home Visit - Post NRC'){
        const nrcEncounter = lastfilledEncounter('NRC Discharge');
        if(nrcEncounter) {
            const nrcEncounterDate = nrcEncounter ? imports.moment(nrcEncounter.encounterDateTime).toDate() : null;
            const visitDate = getChildHomeVisitDate(nrcEncounterDate);

            if (!_.isNil(visitDate)) {
                scheduleBuilder.add({
                    name: 'Child Home Visit - Post NRC',
                    encounterType: 'Child Home Visit',
                    earliestDate: imports.moment(visitDate).startOf('day').toDate(),
                    maxDate: imports.moment(visitDate).add(7, 'days').endOf('day').toDate(),
                    visitCreationStrategy: "createNew"
                });
            }
        }
    }

        return scheduleBuilder.getAll();
    };

"use strict";
({params, imports}) => {
    const programEncounter = params.entity;
    const programEnrolment = programEncounter.programEnrolment;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({programEncounter});

    function isVisitAlreadyScheduled(earliestDate, encounterType, encounterName) {
      const earliestVisitDateTime = moment(earliestDate);
      return programEnrolment.encounters.some(enc => 
        enc.encounterType.name === encounterType && 
        enc.name === encounterName &&
        moment(enc.earliestVisitDateTime).isSame(earliestVisitDateTime, 'day')
      );
    }

    function getChildHomeVisitDate(qrtEncounterDate) {
      const intervalInDays = moment(programEncounter.earliestVisitDateTime).diff(moment(qrtEncounterDate), 'days');

      let daysToAdd = 0;
      if (intervalInDays <= 15) {
        daysToAdd = 30;
      } else if (intervalInDays <= 30) {
        daysToAdd = 45;
      } else if (intervalInDays <= 45) {
        daysToAdd = 60;
      }

      return daysToAdd !== 0 ? moment(qrtEncounterDate).add(daysToAdd, 'days').toDate() : null;
    }

    function lastfilledEncounter(encounterType) {
      const lastVisitEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, false);
      const latestEncounter = _.chain(lastVisitEncounters)
        .filter((encounter) => encounter.encounterDateTime && encounter.voided == false)
        .maxBy((encounter) => encounter.encounterDateTime)
        .value();
      return latestEncounter;
    }

    const qrtEncounter = lastfilledEncounter('QRT Child');
    if (qrtEncounter && programEncounter.name != 'Child Home Visit - Post NRC') {
      const qrtEncounterDate = qrtEncounter ? moment(qrtEncounter.encounterDateTime).toDate() : null;
      const visitDate = getChildHomeVisitDate(qrtEncounterDate);
      const takenToMedicalFacility = qrtEncounter.getObservationReadableValue("QRT facilitated child to medical facility?") == "Yes";
      const latestGMEncounter = lastfilledEncounter('Growth Monitoring');
      const isSAMInLatestGMEncounter = latestGMEncounter.getObservationReadableValue("Nutritional Status") == "SAM";
      const isGF1InLatestGMEncounter = latestGMEncounter.getObservationReadableValue("Growth Faltering") == "GF1";

      if ((takenToMedicalFacility || isSAMInLatestGMEncounter || !isGF1InLatestGMEncounter ) && !_.isNil(visitDate)) { 
        scheduleBuilder.add({
          name: 'Child Home Visit',
          encounterType: 'Child Home Visit',
          earliestDate: moment(visitDate).startOf('day').toDate(),
          maxDate: moment(visitDate).add(7, 'days').endOf('day').toDate(),
          visitCreationStrategy: "createNew"
        });
      }
    }

    if (programEncounter.name == 'Child Home Visit - Post NRC'){
      const nrcEncounter = lastfilledEncounter('NRC Discharge');
      if(nrcEncounter) {
        const nrcDischargeDate = nrcEncounter ? moment(nrcEncounter.getObservationReadableValue('71e84ef3-4f1d-4814-84fc-3672b3a72423')).toDate() : null;
        const visitDate = getChildHomeVisitDate(nrcDischargeDate);

        if (!_.isNil(visitDate) && !isVisitAlreadyScheduled(visitDate, 'Child Home Visit', 'Child Home Visit - Post NRC')) { 
          scheduleBuilder.add({
            name: 'Child Home Visit - Post NRC',
            encounterType: 'Child Home Visit',
            earliestDate: moment(visitDate).startOf('day').toDate(),
            maxDate: moment(visitDate).add(7, 'days').endOf('day').toDate(),
            visitCreationStrategy: "createNew"
          });
        }
      }
    }

    const earliestDate = moment(programEncounter.encounterDateTime);
    const latestGMEncounter = lastfilledEncounter('Growth Monitoring');
    const isSAMInLatestGMEncounter = latestGMEncounter.getObservationReadableValue("Nutritional Status") == "SAM";
    const isMAMInLatestGMEncounter = latestGMEncounter.getObservationReadableValue("Nutritional Status") == "MAM";
    const isGF2InLatestGMEncounter = latestGMEncounter.getObservationReadableValue("Growth Faltering") == "GF2";
    const currentlyActiveInProgram = !programEncounter.programEnrolment.programExitDateTime;
    const supervisorChildEncounter = lastfilledEncounter('Supervisor Child Home visit');
    let schEncounterDate;
    let schEncounterMonth;
    if (supervisorChildEncounter) {
        schEncounterDate = imports.moment(supervisorChildEncounter.encounterDateTime).toDate();
        schEncounterMonth = imports.moment(schEncounterDate).month();
    }      
    const earliestDateMonth = earliestDate.month();


    let isAlreadyScheduled = programEncounter.programEnrolment.encounters.some((enc) =>
        enc.encounterType.name === 'Supervisor Child Home visit' &&
        enc.voided === false &&
        moment(enc.earliestVisitDateTime).isSame(earliestDate, 'day')
    );

    if((schEncounterMonth !== earliestDateMonth) && !isAlreadyScheduled && currentlyActiveInProgram && (isSAMInLatestGMEncounter || isMAMInLatestGMEncounter || isGF2InLatestGMEncounter)) {
        scheduleBuilder.add({
            name: 'Supervisor Child Home visit',
            encounterType: 'Supervisor Child Home visit',
            earliestDate: earliestDate.startOf('day').toDate(),
            maxDate:  earliestDate.endOf('month').toDate()
        });
    }
    return scheduleBuilder.getAll();
};

