'use strict';
({params, imports}) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = '';
  let answersToSkip = [];
  let validationErrors = [];

  const previousANCEncounter = programEncounter.programEnrolment.getEncounters(true).filter(enc => enc.encounterDateTime != null && enc.encounterType.name == 'ANC' && enc.encounterDateTime <= programEncounter.earliestVisitDateTime)

  let highRiskReason = [];
  if(previousANCEncounter.length){
    const hbValue = previousANCEncounter[0].getObservationValue('68bc6e51-eb49-4816-b78b-2427bbab8d92');

    if(hbValue){
       if(hbValue >= 7 && hbValue <= 10.9) highRiskReason.push("Women with mild and moderate Anemia");

       if(hbValue < 7) highRiskReason.push("Women with Severe Anaemia");
    }
  }

  const pregnancyComplications = programEncounter.programEnrolment.getObservationReadableValue('26dcba9f-73b8-4e3a-87c9-de0aa1f928ec');

  const NoOfPregnancyComplications = pregnancyComplications?pregnancyComplications.length:0;

  if(NoOfPregnancyComplications > 0){

    let historyOfPregnancyComplications = '';
    let label = 97;

    for(let ind = 0; ind < NoOfPregnancyComplications; ind++, label++) {
      historyOfPregnancyComplications = historyOfPregnancyComplications + "\t" + String.fromCharCode(label) + ". " + pregnancyComplications[ind];
      if(ind < NoOfPregnancyComplications - 1) historyOfPregnancyComplications = historyOfPregnancyComplications + "\n";
    }

    const pregnancyComplicationObject = {'History of pregnancy complications': historyOfPregnancyComplications};
    highRiskReason.push(pregnancyComplicationObject);
  }

  const pregnancyMorbidityConditions = programEncounter.programEnrolment.getObservationReadableValue('12d99265-c769-4236-aff5-fcba73976396');

  const NoOfPregnancyMorbidityConditions = pregnancyMorbidityConditions?pregnancyMorbidityConditions.length:0;

  if(NoOfPregnancyMorbidityConditions > 0){

    let historyOfMorbidityConditions = '';
    let label = 97;

    for(let ind = 0; ind < NoOfPregnancyMorbidityConditions; ind++, label++) {
      historyOfMorbidityConditions = historyOfMorbidityConditions + "\t" + String.fromCharCode(label) + ". " + pregnancyMorbidityConditions[ind];
      if(ind < NoOfPregnancyMorbidityConditions - 1) historyOfMorbidityConditions = historyOfMorbidityConditions + "\n";
    }

    const pregnancyMorbidityConditionObject = {'Pregnancy induced morbidity conditions': historyOfMorbidityConditions};
    highRiskReason.push(pregnancyMorbidityConditionObject);
  }



  if(previousANCEncounter.length){
    const ANMRecommend = previousANCEncounter[0].getObservationReadableValue('f7cc4fd5-5c66-4695-b5e3-1d83c3621f5d');

    if(ANMRecommend) {
      highRiskReason.push("ANM recommend for a medical facility internetion? (for any reason): " + ANMRecommend);
    }
  }

  const noOfHighRiskReason = highRiskReason.length;
  for(var ind = 0; ind < noOfHighRiskReason; ind++){

    value = value + (ind + 1).toString() + ". " 
    if(typeof highRiskReason[ind] == 'object'){
      const obj = highRiskReason[ind];
      const key = Object.keys(obj)[0];
      value = value + key + ": \n" + obj[key];
    }
    else{
      value = value + highRiskReason[ind];
    }
    if(ind < noOfHighRiskReason - 1) value = value + "\n";
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

